const messages = $input.first().json.messages || [];

const humanMessages = messages.filter(msg => {
  if (!msg.text || msg.text.trim() === '') return false;
  if (msg.subtype) return false;
  if (msg.bot_id) return false;
  if (msg.text.startsWith('joined') || msg.text.startsWith('left')) return false;
  return true;
});

return humanMessages.map(msg => ({
  json: {
    userId: msg.user || 'unknown',
    text: msg.text,
    timestamp: msg.ts,
    threadCount: msg.reply_count || 0
  }
}));

const items = $input.all();
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const formattedMessages = items.map((item, index) => {
  const text = item.json.text || '';
  const userId = item.json.userId || 'Team Member';
  return 'Message ' + (index + 1) + ' (User: ' + userId + '):\n' + text;
}).join('\n\n---\n\n');

return [{
  json: {
    messageCount: items.length,
    today: today,
    formattedStandup: formattedMessages,
    teamName: 'Engineering Team'
  }
}];

