const aiRaw = $input.first().json.message?.content || '{}';
const prevData = $('Format Messages for AI').first().json;

let digest;
try {
  digest = JSON.parse(aiRaw);
} catch (e) {
  digest = {
    summary: aiRaw,
    highlights: [],
    blockers: [],
    teamUpdates: [],
    mood: 'Neutral'
  };
}

const dateStr = new Date().toISOString().split('T')[0];

return [{
  json: {
    date: dateStr,
    today: prevData.today,
    teamName: prevData.teamName,
    messageCount: prevData.messageCount,
    summary: digest.summary || 'No summary generated',
    highlights: (digest.highlights || []).join('\n- '),
    blockers: (digest.blockers || []).join('\n- '),
    teamUpdates: digest.teamUpdates || [],
    teamUpdatesText: (digest.teamUpdates || []).map(u => u.userId + ': ' + u.update).join('\n'),
    mood: digest.mood || 'Neutral'
  }
}];

